const items = $input.all();
const result = [];

const KNOWN_KEYS = {
  "AAAAC3NzaC1lZDI1NTE5AAAAIBXVID774HpPhkFFoywCNyEhmCtS38KvB73zWRw7a421": "Ansible Control Plane",
  "AAAAC3NzaC1lZDI1NTE5AAAAINKcp4DzXr8iAYsMp/IshElBUJPgr9rXqqV5gElgTR7v": "Ansible Control Plane (Rotated)",
  "AAAAC3NzaC1lZDI1NTE5AAAAIMkcEZ18qEIRtCwy4eTrOUOm8raI6dRPViDQS/ES2+pF": "Antigravity AI Agent",
  "AAAAC3NzaC1lZDI1NTE5AAAAIPhwoPRShkqU4cy1On0mZajxPxKNv4ShJM8kdXQ1+MIf": "MacBook Pro (Default Key)",
  "AAAAC3NzaC1lZDI1NTE5AAAAICG/27MedTyW4jTOnctfY2j3J9cjqrmtN4sg1QD4rUFl": "MacBook Pro (yzee-automation-key)",
  "AAAAC3NzaC1lZDI1NTE5AAAAIIXUC0juoJbWiKrYm9H0p9WBlSEzZxvvCGY4XbdGYiIJ": "MacBook Pro (SSH to automation-01)",
  "AAAAC3NzaC1lZDI1NTE5AAAAIAXKIx2/1WOz39JaJGLcGbTAqU4GAH/fJEGd5UmSDhCj": "MacBook Pro (SSH to colmado-db)",
  "AAAAC3NzaC1lZDI1NTE5AAAAILgoT0/+NLB4MrK/g9ol3JMbVvGNquN/2RsS8lmkaV01": "MacBook Pro (SSH to proxmox)",
  "AAAAC3NzaC1lZDI1NTE5AAAAIJTNTA7Z79TVV4SCuHJ7+udf6xCI0uyDb5vaCTPMZEyN": "MacBook Pro (SSH to security-01)",
  "AAAAC3NzaC1lZDI1NTE5AAAAIIxggOpU0ZFAliDXYggUnllfa683WH5b9V7iXMvOBnJf": "MacBook Pro (SSH to windows-lab)"
};

for (const item of items) {
  const data = item.json.body || item.json;
  const ip = data.ip ? data.ip.trim() : "";
  const server = data.server || "Unknown Server";
  const user = data.user || "Unknown User";
  const time = data.time || new Date().toISOString();
  const authInfo = data.auth_info || "";
  const tty = data.tty || "";

  // Extract public key base64 string from SSH_AUTH_INFO_0
  // format: "publickey ssh-ed25519 AAAAC3Nza..."
  let keyBase64 = "";
  if (authInfo.startsWith("publickey ")) {
    const parts = authInfo.split(" ");
    if (parts.length >= 3) {
      keyBase64 = parts[2].trim();
    }
  }

  let clientName = "Unknown Client";
  let category = "Unknown Session";
  let isKnown = false;
  let color = 15158332; // Red (Untrusted)

  // Parse IP octets to detect Tailscale range (100.64.0.0/10)
  const ipParts = ip.split('.');
  const isTailscaleIp = ipParts.length === 4 && ipParts[0] === '100' && (parseInt(ipParts[1], 10) >= 64 && parseInt(ipParts[1], 10) <= 127);

  // 1. Check if Tailscale SSH session
  if (authInfo.startsWith("tailscale-ssh ")) {
    const parts = authInfo.split(" ");
    const tsUser = parts[1];
    const tsNode = parts[2] ? parts[2].replace(".taild490e6.ts.net.", "").replace(".taild490e6.ts.net", "") : "Unknown Node";

    isKnown = true;
    color = 3066993; // Green (Trusted)

    if (tsUser === "ycianno@github" || tsUser === "ycianno@") {
      clientName = "MacBook Pro (via Tailscale SSH)";
      category = `Authorized Tailscale SSH login from ${tsNode}`;
    } else if (tsUser.includes("automation-01") || tsNode.includes("automation-01")) {
      clientName = "Ansible Engine (via Tailscale SSH)";
      category = `System Maintenance / Playbook Execution from ${tsNode}`;
      color = 3447003; // Blue (System)
    } else {
      clientName = `${tsUser} (Tailscale SSH)`;
      category = `Tailscale SSH session from ${tsNode}`;
    }
  }
  // 2. Check if traditional public key is known
  else if (keyBase64 && KNOWN_KEYS[keyBase64]) {
    const keyDesc = KNOWN_KEYS[keyBase64];
    isKnown = true;
    if (keyDesc.includes("Ansible")) {
      clientName = "Ansible Engine (Semaphore)";
      category = "System Maintenance / Playbook Execution";
      color = 3447003; // Blue
    } else if (keyDesc.includes("Antigravity")) {
      clientName = "Antigravity AI Agent (Gemini)";
      category = "AI Coding & Debugging Session";
      color = 9807270; // Purple / Indigo
    } else if (keyDesc.includes("Mac Automation")) {
      clientName = "Mac Automation (Cron/Scripts)";
      category = "Automated CLI / Cron Task";
      color = 3066993; // Green
    } else if (keyDesc.includes("MacBook Pro")) {
      // User's key, check TTY to classify VS Code Remote vs User Terminal
      if (tty === "ssh" || tty === "none" || tty === "") {
        clientName = "VS Code Remote SSH / Claude Agent";
        category = "Editor Backend / Non-Interactive command";
        color = 16750848; // Orange (Authorized)
      } else {
        clientName = "MacBook Pro (User)";
        category = "Interactive Terminal Shell";
        color = 3066993; // Green (Trusted)
      }
    }
  } else if (keyBase64 && keyBase64.includes("claude")) {
    // Placeholder for dedicated Claude key
    clientName = "Claude AI Agent";
    category = "AI Coding Assistant";
    isKnown = true;
    color = 16541467; // Coral/Orange-Red
  } else {
    // No matching key, classify by IP
    if (ip === "10.0.0.67" || ip === "127.0.0.1") {
      clientName = "automation-01 (Localhost)";
      category = "Internal Server Task";
      isKnown = true;
      color = 3066993; // Green
    } else if (ip === "100.115.112.1") {
      clientName = "yzees-mac-mini (Tailscale)";
      category = "Remote Trusted Network Session";
      isKnown = true;
      color = 3066993; // Green (Trusted)
    } else if (isTailscaleIp) {
      clientName = "Tailscale VPN Client";
      category = "Remote Trusted Network Session (Tailscale)";
      isKnown = true;
      color = 3447003; // Blue
    } else if (ip.startsWith("100.96.")) {
      clientName = "Twingate VPN Client";
      category = "Remote Trusted Network Session (Twingate)";
      isKnown = true;
      color = 3447003; // Blue
    } else if (ip.startsWith("10.0.0.")) {
      clientName = "Local DHCP Client";
      category = "Local Subnet Device (Unknown Key)";
      isKnown = false;
      color = 16750848; // Orange
    } else {
      clientName = "Unknown Remote IP";
      category = "UNTRUSTED EXTERNAL IP";
      isKnown = false;
      color = 15158332; // Red (Alert!)
    }
  }

  // Construct rich embed payload for Discord
  const embed = {
    title: isKnown ? "ℹ️ SSH Session: Trusted Client" : "🚨 ALERT: SSH Session: Untrusted/Unknown",
    color: color,
    fields: [
      { name: "Server", value: `\`${server}\``, inline: true },
      { name: "User", value: `\`${user}\``, inline: true },
      { name: "Client IP", value: `\`${ip}\``, inline: true },
      { name: "Detected Client", value: `**${clientName}**`, inline: false },
      { name: "Session Type", value: category, inline: true },
      { name: "TTY", value: `\`${tty || "none"}\``, inline: true },
      { name: "Time", value: time, inline: true }
    ],
    footer: { text: "PAM Session Monitor → n8n Webhook" },
    timestamp: new Date().toISOString()
  };

  result.push({
    json: {
      server,
      user,
      ip,
      time,
      clientName,
      category,
      isKnown,
      color,
      discordPayload: {
        username: "SSH Alert Bot",
        embeds: [embed]
      }
    }
  });
}

return result;
